update public.questions set book_page = 83, source_quote = 'كفر بما أُنزل على محمد ؛ لقول النبي :« مَنْ أَتَى،كَاهِ نًا َفَصَدَّ قَهُ بِمَا يَقُ ولُ فَقَ دْ كَ فَ ر بِمَا أُنْزِلَ عَلَ ى مُحَ مَّد  » .  أكملي الحديث التالي : ع نْ أ بِي هُ ر يْر ة ِ ع نِ النَّبِ ي ق ال :« مَنْ أَتَى ....كَاهِ نًا فَصَدَّ قَهُ بِمَا يَقُ ولُ فَقَ دْ كَ' where id = '4bf8602f-a602-45dc-8ba3-ac52b6cc6df9';
