update public.questions set book_page = 96, source_quote = '« ِمُ طِ رْن ا بِف ضْلِ َّللاَّ ِ و ر حْ م تِه» . مل ا كان نسبة نزول المطر إلى النوء على وجه االعتقاد-أن له تأثيراً في نزوله- ًشركا أكبر كاعتقاد جلب النفع أو دفع الضر في األموات والغائبين، أو شركاً أصغر إن كان ال يعتقد أن لها تأثيراً وإنما هي أسباب لنزول المطر ناسب أن ي عقد له .ا' where id = '92a8d4e6-cd55-424e-9a9f-17bdd31b861b';
update public.questions set book_page = 99, source_quote = '«قَالَ أَصْبَحَ مِنْ عِبَادِ ي مُؤْمِنٌ بِي، ٌوَكَافِر َفَأَمَّا مَنْ قَال : ِ َّمُطِ رْنَا بِفَ ضْلِ َّللا ، ِوَرَحْ مَتِه ٌفَذَ لِكَ مُؤْمِنٌ بِي كَافِر، ِبِالْكَ وْكَ ب َوَأَمَّا مَنْ قَال : مُطِ رْنَا بِنَوْ ءِ كَ ذَ ا،وَكَ ذَ ا فَذَ لِكَ كَافِرٌ بِي َمُؤْمِنٌ بِالْكَ وْك ِب»' where id = 'fabf0772-732e-463b-92b2-d086fe371727';
