update public.questions set book_page = 47, source_quote = 'يشترون أنفسهم بالدخول في الإسلام، وتوحيد الله عز وجل، وترك عبادة ما سواه، هذا هو الذي يشترون به أنفسهم، فافتداء اإلنسان نفسه من النار إنما يكون بطاعة الله، وطاعة رسوله ، وبدون ذلك ال يمكن أن ينجو من عذاب الله، ولو قدم األموال الطائلة، فمن مات على الكفر، فإنه لو قدم ملء األرض من ' where id = '48ee7845-f5f6-4d90-9da0-6f890e9ca6dc';
