update public.questions set book_page = 83, source_quote = 'كفر بما أُنزل على محمد ؛ لقول النبي :« مَنْ أَتَى،كَاهِ نًا َفَصَدَّ قَهُ بِمَا يَقُ ولُ فَقَ دْ كَ فَ ر بِمَا أُنْزِلَ عَلَ ى مُحَ مَّد  » .  أكملي الحديث التالي : ع نْ أ بِي هُ ر يْر ة ِ ع نِ النَّبِ ي ق ال :« مَنْ أَتَى ....كَاهِ نًا فَصَدَّ قَهُ بِمَا يَقُ ولُ فَقَ دْ كَ' where id = '24b979bd-760c-41d7-ac3e-33412c2bb0b8';
