update public.questions set book_page = 135, source_quote = '.العطف بالواو يقتض ي الجمع والمساواة العطف بثُم .يقتض ي الترتيب والتراخي العبارة األولى فيها تشريك ومساوة بالله، ألنه من اتخاذ األنداد لله الذي نهتْ عنه اآلية التي في أول الباب على ما فسرها به ابن عباس، وجواز قول :«ما شاء الله ثم شئت» ، وما أشبه ذلك .مما فيه العطف على الله بثُمَّ' where id = '8f6895fa-fbc1-4793-b647-f20999d7a041';
