update public.questions set book_page = 1, source_quote = ' : ت رج مة الراوي هو عمر بن اخلطاب بن نوفل القريش ،العدوي ثاين اخللفاء الراشدين و أ َّحد العرشة المبرشين باجلنة وأول من سيم بأمي المؤمنني كن اه انليب  بأيب حفص ولقبه الفاروق لنه اكن يفرق بني الحق وابلاطل وهو أول من جهر بالإسلام ومن فضائله أن الشيطان اكن يفر منه' where id = 'd3fa8f26-757b-4a00-8449-35e81a4014d1';
update public.questions set book_page = 3, source_quote = ' : ت رج مة الراوي عبدالله بن عمر بن اخلطاب بن نفيل القريش،العدوي أسلم مع أبيه بمكة وهو صغي وهاجر معه إ لى المدينة واكن من فقهاء الصحابة شهد اخلندق وبيعة الرضوان تويف بمكة يف السنة اثلاثلة والسبعني من اهلجرة انلبوية ' where id = '31d613b7-3a50-4285-9f06-5fec89170b83';
