update public.questions set book_page = 20, source_quote = 'وأن محمد:ا رسول الله طاعته فيما أمر وتصديقه فيما أخب واجتناب ما .نىه عنه وزجر وأال يعبد الله إال بما رشع :الصالة اتلعبد لله بأقوالوأفعالمعلومة مبتدئة باتلكبي وخمتتمة .بالتسليم :إيتاء .إعطاء :الزاكة ًعبادة مايلة مقدرة رشاع يف أصناف معينة يرصف لطائفة خمصوصة .بنية خمصوصة :الصوم ًاتل' where id = '85144bc0-eed2-4866-bbf6-53aaf7d73d38';
